#!/usr/bin/env python3
"""XLAB Brand Assets - base64 encoded PNG files with transparency.
Run this script to extract assets to a target directory.
Usage: python3 extract_assets.py [output_dir]
"""
import base64, os, sys

TARGET = sys.argv[1] if len(sys.argv) > 1 else "/tmp/xlab-assets"
os.makedirs(TARGET, exist_ok=True)

ASSETS = {
    "x_logo_black": "",
    "x_logo_white": "",
    "x_symbol_black": "",
    "x_symbol_white": "",
}

for name, data in ASSETS.items():
    out_path = os.path.join(TARGET, f"{name}.png")
    with open(out_path, "wb") as f:
        f.write(base64.b64decode(data))
    print(f"Extracted: {out_path}")

print(f"\nAll assets extracted to {TARGET}")
